29	// Executions is the resolver for the executions field.
30	func (r *queryResolver) Executions(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, beadID *string, verdict *string, harness *string, since *string, until *string, search *string) (*ExecutionConnection, error) {
31		provider, ok := r.State.(ExecutionsStateProvider)
32		if !ok {
33			return emptyExecutionConnection(), nil
34		}
35		filter := ExecutionFilter{}
36		if beadID != nil {
37			filter.BeadID = *beadID
38		}
39		if verdict != nil {
40			filter.Verdict = *verdict
41		}
42		if harness != nil {
43			filter.Harness = *harness
44		}
45		if search != nil {
46			filter.Search = *search
47		}
48		if since != nil && *since != "" {
49			if t, err := time.Parse(time.RFC3339, *since); err == nil {
50				filter.Since = &t
51			}
52		}
53		if until != nil && *until != "" {
54			if t, err := time.Parse(time.RFC3339, *until); err == nil {
55				filter.Until = &t
56			}
57		}
58		all := provider.GetExecutionsGraphQL(projectID, filter)
59		return executionConnectionFrom(all, first, after, last, before), nil
60	}
61	
