115	func emptyExecutionConnection() *ExecutionConnection {
116		return &ExecutionConnection{Edges: []*ExecutionEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
117	}
118	
119	func emptyToolCallConnection() *ExecutionToolCallConnection {
120		return &ExecutionToolCallConnection{Edges: []*ExecutionToolCallEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
121	}
122	
123	func executionConnectionFrom(execs []*Execution, first *int, after *string, last *int, before *string) *ExecutionConnection {
124		all := make([]*ExecutionEdge, len(execs))
125		ids := make([]string, len(execs))
126		for i, e := range execs {
127			all[i] = &ExecutionEdge{Node: e, Cursor: encodeStableCursor(e.ID)}
128			ids[i] = e.ID
129		}
130		startIdx, endIdx := stablePageBounds(ids, after, before)
131		slice := all[startIdx:endIdx]
132		truncByFirst, truncByLast := false, false
133		if first != nil && *first >= 0 && *first < len(slice) {
134			slice = slice[:*first]
135			truncByFirst = true
136		}
137		if last != nil && *last >= 0 && *last < len(slice) {
138			slice = slice[len(slice)-*last:]
139			truncByLast = true
140		}
141		pageInfo := &PageInfo{
142			HasPreviousPage: startIdx > 0 || truncByLast,
143			HasNextPage:     endIdx < len(all) || truncByFirst,
144		}
145		if len(slice) > 0 {
146			pageInfo.StartCursor = &slice[0].Cursor
147			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
148		}
149		return &ExecutionConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
150	}
151	
152	func toolCallConnectionFrom(calls []*ExecutionToolCall, first *int, after *string) *ExecutionToolCallConnection {
153		all := make([]*ExecutionToolCallEdge, len(calls))
154		ids := make([]string, len(calls))
155		for i, c := range calls {
156			all[i] = &ExecutionToolCallEdge{Node: c, Cursor: encodeStableCursor(c.ID)}
157			ids[i] = c.ID
158		}
159		startIdx, _ := stablePageBounds(ids, after, nil)
160		slice := all[startIdx:]
161		truncByFirst := false
162		if first != nil && *first >= 0 && *first < len(slice) {
163			slice = slice[:*first]
164			truncByFirst = true
165		}
166		pageInfo := &PageInfo{
167			HasPreviousPage: startIdx > 0,
168			HasNextPage:     truncByFirst,
169		}
170		if len(slice) > 0 {
171			pageInfo.StartCursor = &slice[0].Cursor
172			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
173		}
174		return &ExecutionToolCallConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
175	}
