142	// GetBeadSnapshot implements ddxgraphql.StateProvider.
143	func (s *ServerState) GetBeadSnapshot(id string) (*ddxgraphql.BeadSnapshot, bool) {
144		if id == "" {
145			return nil, false
146		}
147	
148		if loc, ok := s.lookupBeadLocation(id); ok {
149			proj := ProjectEntry{ID: loc.ProjectID, Path: loc.ProjectPath}
150			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
151				return snap, true
152			}
153			s.forgetBeadLocation(id)
154		}
155	
156		for _, proj := range s.GetProjects() {
157			if snap, ok := readBeadSnapshotFromProject(proj, id); ok {
158				s.rememberBeadLocation(id, proj)
159				return snap, true
160			}
161		}
162		return nil, false
163	}
164	
165	func (s *ServerState) rememberBeadLocation(id string, proj ProjectEntry) {
166		if id == "" || proj.ID == "" || proj.Path == "" {
167			return
168		}
169		s.beadIndexMu.Lock()
170		defer s.beadIndexMu.Unlock()
171		if s.beadIndex == nil {
172			s.beadIndex = make(map[string]beadIndexEntry)
173		}
174		s.beadIndex[id] = beadIndexEntry{ProjectID: proj.ID, ProjectPath: proj.Path}
175	}
176	
177	func (s *ServerState) lookupBeadLocation(id string) (beadIndexEntry, bool) {
178		s.beadIndexMu.RLock()
179		defer s.beadIndexMu.RUnlock()
180		if s.beadIndex == nil {
181			return beadIndexEntry{}, false
182		}
183		loc, ok := s.beadIndex[id]
184		return loc, ok
185	}
186	
187	func (s *ServerState) forgetBeadLocation(id string) {
188		s.beadIndexMu.Lock()
189		defer s.beadIndexMu.Unlock()
190		delete(s.beadIndex, id)
191	}
192	
193	func readBeadSnapshotFromProject(proj ProjectEntry, id string) (*ddxgraphql.BeadSnapshot, bool) {
194		store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
195		b, err := store.Get(id)
196		if err != nil {
197			return nil, false
198		}
199		snap := beadSnapshotFromStoreBead(proj.ID, *b)
200		return &snap, true

