51	func (a *workerDispatchAdapter) DispatchWorker(ctx context.Context, kind string, projectRoot string, rawArgs *string) (*ddxgraphql.WorkerDispatchResult, error) {
52		if a == nil || a.manager == nil {
53			return nil, fmt.Errorf("worker dispatcher is not configured")
54		}
55		if err := ctx.Err(); err != nil {
56			return nil, err
57		}
58		if kind != "execute-loop" {
59			return nil, fmt.Errorf("unsupported worker kind %q", kind)
60		}
61	
62		var req struct {
63			Harness       string `json:"harness"`
64			Model         string `json:"model"`
65			Profile       string `json:"profile"`
66			Provider      string `json:"provider"`
67			ModelRef      string `json:"model_ref"`
68			Effort        string `json:"effort"`
69			LabelFilter   string `json:"label_filter"`
70			Once          bool   `json:"once"`
71			PollInterval  string `json:"poll_interval"`
72			NoReview      bool   `json:"no_review"`
73			ReviewHarness string `json:"review_harness"`
74			ReviewModel   string `json:"review_model"`
75		}
76		if rawArgs != nil && *rawArgs != "" {
77			if err := json.Unmarshal([]byte(*rawArgs), &req); err != nil {
78				return nil, fmt.Errorf("invalid worker args JSON: %w", err)
79			}
80		}
81	
82		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
83		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
84		// for this project so the "+ Add worker" button can refuse cleanly.
85		if wc := loadWorkersConfig(projectRoot); wc != nil {
86			if spec := wc.DefaultSpec; spec != nil {
87				if req.Harness == "" {
88					req.Harness = spec.Harness
89				}
90				if req.Profile == "" {
91					req.Profile = spec.Profile
92				}
93				if req.Effort == "" {
94					req.Effort = spec.Effort
95				}
96			}
97			if wc.MaxCount != nil && *wc.MaxCount >= 0 {
98				running := a.countRunningDrainWorkers(projectRoot)
99				if running >= *wc.MaxCount {
100					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
101				}
102			}
103		}
104	
105		// Default-path contract (ddx-755f5881 AC #1): an empty dispatch input
106		// (no rawArgs, no workers.default_spec) must produce a spec with
107		// Profile: "default" and nothing else. This eliminates the historical
108		// 19-burn drain-queue failure mode where an empty spec fanned out into
109		// per-tier ladder iteration with no upstream synthesis target.
110		if req.Profile == "" {
111			req.Profile = "default"
112		}
113	
114		var pollInterval time.Duration
115		if req.PollInterval != "" {
116			d, err := time.ParseDuration(req.PollInterval)
117			if err != nil {
118				return nil, fmt.Errorf("invalid poll_interval: %w", err)
119			}
120			pollInterval = d
121		}
122	
123		record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
124			ProjectRoot:   projectRoot,
125			Harness:       req.Harness,
126			Model:         req.Model,
127			Profile:       req.Profile,
128			Provider:      req.Provider,
129			ModelRef:      req.ModelRef,
130			Effort:        req.Effort,
131			LabelFilter:   req.LabelFilter,
132			Once:          req.Once,
133			PollInterval:  pollInterval,
134			NoReview:      req.NoReview,
135			ReviewHarness: req.ReviewHarness,
136			ReviewModel:   req.ReviewModel,
137		})
138		if err != nil {
139			return nil, err
140		}
141		return &ddxgraphql.WorkerDispatchResult{
142			ID:    record.ID,
143			State: record.State,
144			Kind:  record.Kind,
145		}, nil
146	}
