483	// Projects is the resolver for the projects field.
484	func (r *queryResolver) Projects(ctx context.Context, first *int, after *string, last *int, before *string, includeUnreachable *bool) (*ProjectConnection, error) {
485		showAll := includeUnreachable != nil && *includeUnreachable
486		projects := r.State.GetProjectSnapshots(showAll)
487	
488		// Build full edge list with stable ID-based cursors.
489		all := make([]*ProjectEdge, len(projects))
490		for i, p := range projects {
491			all[i] = &ProjectEdge{
492				Node:   p,
493				Cursor: encodeStableCursor(p.ID),
494			}
495		}
496	
497		// Apply window: start after `after` cursor, end before `before` cursor.
498		startIdx := 0
499		if after != nil {
500			if afterID, ok := decodeStableCursor(*after); ok {
501				for i, e := range all {
502					if e.Node.ID == afterID {
503						startIdx = i + 1
504						break
505					}
506				}
507			}
508		}
509		endIdx := len(all)
510		if before != nil {
511			if beforeID, ok := decodeStableCursor(*before); ok {
512				for i, e := range all {
513					if e.Node.ID == beforeID {
514						endIdx = i
515						break
516					}
517				}
518			}
519		}
520		if startIdx > endIdx {
521			startIdx = endIdx
522		}
523	
524		slice := all[startIdx:endIdx]
525		if first != nil && *first >= 0 && *first < len(slice) {
526			slice = slice[:*first]
527		}
528		if last != nil && *last >= 0 && *last < len(slice) {
529			slice = slice[len(slice)-*last:]
530		}
531	
532		pageInfo := &PageInfo{
533			HasPreviousPage: startIdx > 0,
534			HasNextPage:     endIdx < len(all),
535		}
536		if len(slice) > 0 {
537			pageInfo.StartCursor = &slice[0].Cursor
538			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
539		}
540	
541		return &ProjectConnection{
542			Edges:      slice,
543			PageInfo:   pageInfo,
544			TotalCount: len(all),
545		}, nil
546	}
