613	// Documents is the resolver for the documents field with Relay cursor pagination.
614	func (r *queryResolver) Documents(ctx context.Context, first *int, after *string, last *int, before *string, typeArg *string) (*DocumentConnection, error) {
615		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
616		if err != nil {
617			return nil, fmt.Errorf("building document graph: %w", err)
618		}
619	
620		docs := graph.AllNodesForOutput()
621		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
622	
623		// Apply optional type filter by path component.
624		if typeArg != nil && *typeArg != "" {
625			filtered := docs[:0]
626			for _, d := range docs {
627				if strings.Contains(d.Path, string([]rune{'/'})+*typeArg+string([]rune{'/'})) ||
628					strings.HasPrefix(d.Path, *typeArg+string([]rune{'/'})) {
629					filtered = append(filtered, d)
630				}
631			}
632			docs = filtered
633		}
634	
635		all := make([]*DocumentEdge, len(docs))
636		for i, d := range docs {
637			all[i] = &DocumentEdge{
638				Node:   docToGQL(d),
639				Cursor: encodeStableCursor(d.ID),
640			}
641		}
642	
643		startIdx := 0
644		if after != nil {
645			if afterID, ok := decodeStableCursor(*after); ok {
646				for i, e := range all {
647					if e.Node.ID == afterID {
648						startIdx = i + 1
649						break
650					}
651				}
652			}
653		}
654		endIdx := len(all)
655		if before != nil {
656			if beforeID, ok := decodeStableCursor(*before); ok {
657				for i, e := range all {
658					if e.Node.ID == beforeID {
659						endIdx = i
660						break
661					}
662				}
663			}
664		}
665		if startIdx > endIdx {
666			startIdx = endIdx
667		}
668	
669		slice := all[startIdx:endIdx]
670		if first != nil && *first >= 0 && *first < len(slice) {
671			slice = slice[:*first]
672		}
673		if last != nil && *last >= 0 && *last < len(slice) {
674			slice = slice[len(slice)-*last:]
675		}
676	
677		pageInfo := &PageInfo{
678			HasPreviousPage: startIdx > 0,
679			HasNextPage:     endIdx < len(all),
680		}
681		if len(slice) > 0 {
682			pageInfo.StartCursor = &slice[0].Cursor
683			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
684		}
685	
686		return &DocumentConnection{
687			Edges:      slice,
688			PageInfo:   pageInfo,
689			TotalCount: len(all),
690		}, nil
691	}
