758	// DocGraph is the resolver for the docGraph field.
759	func (r *queryResolver) DocGraph(ctx context.Context) (*DocGraph, error) {
760		graph, err := docgraph.BuildGraphWithConfig(r.WorkingDir)
761		if err != nil {
762			return nil, fmt.Errorf("building document graph: %w", err)
763		}
764	
765		docs := graph.AllNodesForOutput()
766		sort.Slice(docs, func(i, j int) bool { return docs[i].ID < docs[j].ID })
767		gqlDocs := make([]*Document, len(docs))
768		for i, d := range docs {
769			gqlDocs[i] = docToGQL(d)
770		}
771	
772		pathToIDJSON, err := json.Marshal(graph.PathToID)
773		if err != nil {
774			return nil, fmt.Errorf("serializing pathToId: %w", err)
775		}
776		dependentsJSON, err := json.Marshal(graph.Dependents)
777		if err != nil {
778			return nil, fmt.Errorf("serializing dependents: %w", err)
779		}
780	
781		warnings := graph.Warnings
782		if warnings == nil {
783			warnings = []string{}
784		}
785	
786		return &DocGraph{
787			RootDir:    graph.RootDir,
788			Documents:  gqlDocs,
789			PathToID:   string(pathToIDJSON),
790			Dependents: string(dependentsJSON),
791			Warnings:   warnings,
792			Issues:     issuesToGQL(graph.Issues),
793		}, nil
794	}
