847	// Commits is the resolver for the commits field.
848	func (r *queryResolver) Commits(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, since *string, author *string) (*CommitConnection, error) {
849		proj, ok := r.State.GetProjectSnapshotByID(projectID)
850		if !ok {
851			return nil, fmt.Errorf("project not found: %s", projectID)
852		}
853	
854		snaps, err := gitLogCommits(ctx, proj.Path, since, author)
855		if err != nil {
856			return nil, err
857		}
858	
859		// Build full edge list with stable SHA-based cursors.
860		all := make([]*CommitEdge, len(snaps))
861		for i, c := range snaps {
862			all[i] = &CommitEdge{
863				Node:   c,
864				Cursor: encodeStableCursor(c.Sha),
865			}
866		}
867	
868		// Apply window: start after `after` cursor, end before `before` cursor.
869		startIdx := 0
870		if after != nil {
871			if afterSha, ok := decodeStableCursor(*after); ok {
872				for i, e := range all {
873					if e.Node.Sha == afterSha {
874						startIdx = i + 1
875						break
876					}
877				}
878			}
879		}
880		endIdx := len(all)
881		if before != nil {
882			if beforeSha, ok := decodeStableCursor(*before); ok {
883				for i, e := range all {
884					if e.Node.Sha == beforeSha {
885						endIdx = i
886						break
887					}
888				}
889			}
890		}
891		if startIdx > endIdx {
892			startIdx = endIdx
893		}
894	
895		windowSize := endIdx - startIdx
896		slice := all[startIdx:endIdx]
897		if first != nil && *first >= 0 && *first < len(slice) {
898			slice = slice[:*first]
899		}
900		if last != nil && *last >= 0 && *last < len(slice) {
901			slice = slice[len(slice)-*last:]
902		}
903	
904		pageInfo := &PageInfo{
905			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
906			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
907		}
908		if len(slice) > 0 {
909			pageInfo.StartCursor = &slice[0].Cursor
910			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
911		}
912	
913		return &CommitConnection{
914			Edges:      slice,
915			PageInfo:   pageInfo,
916			TotalCount: len(all),
917		}, nil
918	}
