1220	// ProviderStatuses is the resolver for the providerStatuses field.
1221	// It mirrors the output of `ddx agent providers`, annotating each row with
1222	// kind=ENDPOINT, a lastCheckedAt timestamp, and rolling usage derived from
1223	// the sessions index. Quota is populated when the upstream ProviderInfo
1224	// exposes token-level quota headers; null otherwise (FEAT-014 no-fabrication).
1225	func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
1226		now := time.Now().UTC()
1227		entries := r.sessionIndexEntries()
1228	
1229		if rows := cachedProviderRows(r.WorkingDir); len(rows) > 0 {
1230			refreshProviderStatuses(r.WorkingDir)
1231			return providerRowsWithUsage(rows, entries, now), nil
1232		}
1233	
1234		if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.WorkingDir); err == nil && ok {
1235			rows := providerStatusesFromInfos(snapshots, entries, now)
1236			storeProviderRows(r.WorkingDir, rows)
1237			refreshProviderStatuses(r.WorkingDir)
1238			return rows, nil
1239		} else if err != nil {
1240			return nil, fmt.Errorf("loading provider snapshots: %w", err)
1241		}
1242	
1243		// Legacy/global provider config fallback. Bound the synchronous path so the
1244		// UI can still first-paint harness rows even if provider probing is slow.
1245		probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
1246		defer cancel()
1247		providers, err := liveProviderInfos(probeCtx, r.WorkingDir)
1248		if err != nil {
1249			refreshProviderStatuses(r.WorkingDir)
1250			return []*ProviderStatus{}, nil
1251		}
1252		rows := providerStatusesFromInfos(providers, entries, now)
1253		storeProviderRows(r.WorkingDir, rows)
1254		return rows, nil
1255	}
