1257	// HarnessStatuses is the resolver for the harnessStatuses field.
1258	// It returns one row per subprocess harness (kind=HARNESS). Reachability is
1259	// taken from HarnessInfo.Available, rolling usage from the sessions index,
1260	// and quota from the harness-reported rate-limit data when available.
1261	func (r *queryResolver) HarnessStatuses(ctx context.Context) ([]*ProviderStatus, error) {
1262		svc, err := agentlib.New(agentlib.ServiceOptions{})
1263		if err != nil {
1264			return []*ProviderStatus{}, nil //nolint:nilerr
1265		}
1266		infos, err := svc.ListHarnesses(ctx)
1267		if err != nil {
1268			return nil, fmt.Errorf("listing harnesses: %w", err)
1269		}
1270	
1271		now := time.Now().UTC()
1272		entries := r.sessionIndexEntries()
1273		lastChecked := now.Format(time.RFC3339)
1274	
1275		results := make([]*ProviderStatus, 0, len(infos))
1276		for _, info := range infos {
1277			ps := &ProviderStatus{
1278				Name:              info.Name,
1279				Kind:              ProviderKindHarness,
1280				ProviderType:      harnessTypeLabel(info),
1281				BaseURL:           "(subprocess)",
1282				Model:             info.DefaultModel,
1283				Status:            harnessStatusLine(info),
1284				Reachable:         info.Available,
1285				Detail:            harnessDetail(info),
1286				ModelCount:        harnessModelCount(info),
1287				IsDefault:         false,
1288				LastCheckedAt:     strPtr(lastChecked),
1289				DefaultForProfile: []string{},
1290			}
1291			ps.Usage = buildUsage(entries, info.Name, agent.MatchHarness, now)
1292			ps.Quota = quotaFromHarnessInfo(info)
1293			ps.Sparkline = buildSparkline(entries, info.Name, agent.MatchHarness, now)
1294			results = append(results, ps)
1295		}
1296	
1297		return results, nil
1298	}
