1322	// ProviderTrend is the resolver for the providerTrend field.
1323	// It aggregates the sessions index into time buckets for one provider/harness
1324	// and computes a projected-run-out-in-hours callout from the last-24h slope.
1325	func (r *queryResolver) ProviderTrend(ctx context.Context, name string, windowDays int) (*ProviderTrend, error) {
1326		name = strings.TrimSpace(name)
1327		if name == "" {
1328			return nil, fmt.Errorf("name required")
1329		}
1330		if windowDays != 7 && windowDays != 30 {
1331			return nil, fmt.Errorf("windowDays must be 7 or 30")
1332		}
1333		now := time.Now().UTC()
1334		entries := r.sessionIndexEntries()
1335	
1336		kind, detected := detectProviderOrHarness(ctx, r, name)
1337		bucketKind := agent.MatchProvider
1338		if kind == ProviderKindHarness {
1339			bucketKind = agent.MatchHarness
1340		}
1341	
1342		bucketSize := time.Hour
1343		if windowDays > 7 {
1344			bucketSize = 4 * time.Hour
1345		}
1346		buckets := agent.BucketUsage(entries, name, bucketKind, now, windowDays, bucketSize)
1347		series := make([]*ProviderTrendPoint, 0, len(buckets))
1348		for _, b := range buckets {
1349			series = append(series, &ProviderTrendPoint{
1350				BucketStart: b.Start.UTC().Format(time.RFC3339),
1351				Tokens:      b.Tokens,
1352				Requests:    b.Requests,
1353			})
1354		}
1355	
1356		trend := &ProviderTrend{
1357			Name:       name,
1358			Kind:       kind,
1359			WindowDays: windowDays,
1360			Series:     series,
1361		}
1362	
1363		if detected != nil {
1364			if ceiling := detected.ceilingTokens; ceiling > 0 {
1365				c := ceiling
1366				trend.CeilingTokens = &c
1367				remaining := detected.remaining
1368				if remaining < 0 {
1369					remaining = ceiling - sumTailTokens(buckets, 24)
1370				}
1371				if p := projectRunOutHours(buckets, float64(remaining)); p > 0 {
1372					trend.ProjectedRunOutHours = &p
1373				}
1374			}
1375		}
1376	
1377		return trend, nil
1378	}
