1408	// QueueAndWorkersSummary backs the global drain indicator (ddx-b6cf025c).
1409	// Returns zeros — not an error — for unknown or empty projects so the nav
1410	// component can render without special-casing failures.
1411	func (r *queryResolver) QueueAndWorkersSummary(ctx context.Context, projectID string) (*QueueAndWorkersSummary, error) {
1412		out := &QueueAndWorkersSummary{}
1413		// Only resolve ready beads when the projectID maps to a real project.
1414		// Unknown IDs return zeros rather than falling back to WorkingDir so the
1415		// indicator does not surface an unrelated project's queue depth.
1416		if r.State != nil {
1417			if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
1418				store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
1419				if ready, err := store.Ready(); err == nil {
1420					out.ReadyBeads = len(ready)
1421				}
1422			}
1423			workers := r.State.GetWorkersGraphQL(projectID)
1424			out.TotalWorkers = len(workers)
1425			for _, w := range workers {
1426				if w != nil && w.State == "running" {
1427					out.RunningWorkers++
1428				}
