1710			return nil, fmt.Errorf("subscription not available: coordinator metrics provider not configured")
1711		}
1712	
1713		interval := r.MetricsPollInterval
1714		if interval <= 0 {
1715			interval = time.Second
1716		}
1717	
1718		out := make(chan *CoordinatorMetricsUpdate, 16)
1719		go func() {
1720			defer close(out)
1721			var last CoordinatorMetricsSnap
1722			hasPrev := false
1723			seq := 0
1724			ticker := time.NewTicker(interval)
1725			defer ticker.Stop()
1726			for {
1727				select {
1728				case <-ctx.Done():
1729					return
1730				case <-ticker.C:
1731					snap := r.CoordMetrics.GetCoordinatorMetrics(projectRoot)
1732					if snap == nil {
1733						continue
1734					}
1735					if hasPrev && *snap == last {
1736						continue
1737					}
1738					hasPrev = true
1739					last = *snap
1740					seq++
1741					ts := time.Now().UTC().Format(time.RFC3339)
1742					update := &CoordinatorMetricsUpdate{
1743						UpdateID:        fmt.Sprintf("%s-update-%d", projectRoot, seq),
1744						ProjectRoot:     projectRoot,
1745						Timestamp:       ts,
1746						Landed:          int(snap.Landed),
1747						Preserved:       int(snap.Preserved),
1748						Failed:          int(snap.Failed),
1749						PushFailed:      int(snap.PushFailed),
1750						TotalDurationMs: int(snap.TotalDurationMS),
1751						TotalCommits:    int(snap.TotalCommits),
1752					}
1753					select {
1754					case out <- update:
1755					case <-ctx.Done():
1756						return
1757					}
1758				}
1759			}
1760		}()
1761		return out, nil
1762	}
