152	func newTestStateProvider(workDir string, store *bead.Store) *testStateProvider {
153		now := time.Now()
154		projID := "proj-integration-" + filepath.Base(workDir)
155	
156		allBeads, _ := store.ReadAll()
157		snaps := make([]ddxgraphql.BeadSnapshot, 0, len(allBeads))
158		for _, b := range allBeads {
159			snaps = append(snaps, ddxgraphql.BeadSnapshot{
160				ProjectID: projID,
