162				Title:     b.Title,
163				Status:    b.Status,
164				Priority:  b.Priority,
165				IssueType: b.IssueType,
166				Owner:     b.Owner,
167				CreatedAt: b.CreatedAt,
168				UpdatedAt: b.UpdatedAt,
169				Labels:    b.Labels,
170			})
171		}
172	
173		registeredAt := now.Add(-time.Hour).UTC().Format(time.RFC3339)
174		lastSeen := now.UTC().Format(time.RFC3339)
175		return &testStateProvider{
176			node: ddxgraphql.NodeStateSnapshot{
177				ID:        "node-integration-test",
178				Name:      "integration-test-node",
179				StartedAt: now.Add(-time.Hour),

