func setupArtifactFixture(t *testing.T) (workDir string) {
	t.Helper()
	workDir, _ = setupIntegrationDir(t)

	// Markdown document with DDx frontmatter (picked up by docgraph).
	docsDir := filepath.Join(workDir, "docs")
	if err := os.MkdirAll(docsDir, 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(filepath.Join(docsDir, "spec.md"), []byte(
		"---\nddx:\n  id: spec-001\n  title: Project Spec\n---\n# Project Spec\n\nContent here.\n",
	), 0o644); err != nil {
		t.Fatal(err)
	}

	// DDx config so the docgraph walker knows where the root is.
	ddxDir := filepath.Join(workDir, ".ddx")
	cfgPath := filepath.Join(ddxDir, "config.yaml")
	if err := os.WriteFile(cfgPath, []byte("version: \"1.0\"\nbead:\n  id_prefix: \"art\"\n"), 0o644); err != nil {
		t.Fatal(err)
	}

	// Image artifact with .ddx.yaml sidecar.
	assetsDir := filepath.Join(ddxDir, "plugins", "assets")
	if err := os.MkdirAll(assetsDir, 0o755); err != nil {
		t.Fatal(err)
	}
	pngData := []byte("\x89PNG\r\n\x1a\n") // minimal PNG-like header
	if err := os.WriteFile(filepath.Join(assetsDir, "diagram.png"), pngData, 0o644); err != nil {
